4: package views
5: 
6: import (
7: 	"testing"
8: 
9: 	"github.com/zclconf/go-cty/cty"
10: 
11: 	"github.com/hashicorp/terraform/internal/addrs"
12: 	"github.com/hashicorp/terraform/internal/command/arguments"
