14: 	"github.com/hashicorp/terraform/internal/plans"
15: 	"github.com/hashicorp/terraform/internal/providers"
16: 	testing_provider "github.com/hashicorp/terraform/internal/providers/testing"
17: 	"github.com/hashicorp/terraform/internal/terminal"
18: 	"github.com/hashicorp/terraform/internal/terraform"
19: )
20: 
21: // Ensure that the correct view type and in-automation settings propagate to the
22: // Operation view.
23: func TestPlanHuman_operation(t *testing.T) {
24: 	streams, done := terminal.StreamsForTesting(t)
25: 	defer done(t)
26: 	v := NewPlan(arguments.ViewHuman, NewView(streams).SetRunningInAutomation(true)).Operation()
27: 	if hv, ok := v.(*OperationHuman); !ok {
28: 		t.Fatalf("unexpected return type %t", v)
29: 	} else if hv.inAutomation != true {
30: 		t.Fatalf("unexpected inAutomation value on Operation view")
31: 	}
32: }
33: 
34: // Verify that Hooks includes a UI hook
35: func TestPlanHuman_hooks(t *testing.T) {
36: 	streams, done := terminal.StreamsForTesting(t)
37: 	defer done(t)
38: 	v := NewPlan(arguments.ViewHuman, NewView(streams).SetRunningInAutomation((true)))
39: 	hooks := v.Hooks()
40: 
41: 	var uiHook *UiHook
42: 	for _, hook := range hooks {
43: 		if ch, ok := hook.(*UiHook); ok {
44: 			uiHook = ch
45: 		}
46: 	}
47: 	if uiHook == nil {
48: 		t.Fatalf("expected Hooks to include a UiHook: %#v", hooks)
49: 	}
50: }
51: 
52: // Helper functions to build a trivial test plan, to exercise the plan
53: // renderer.
54: func testPlan(t *testing.T) *plans.Plan {
55: 	t.Helper()
56: 
57: 	plannedVal := cty.ObjectVal(map[string]cty.Value{
58: 		"id":  cty.UnknownVal(cty.String),
59: 		"foo": cty.StringVal("bar"),
60: 	})
61: 	priorValRaw, err := plans.NewDynamicValue(cty.NullVal(plannedVal.Type()), plannedVal.Type())
62: 	if err != nil {
63: 		t.Fatal(err)
64: 	}
65: 	plannedValRaw, err := plans.NewDynamicValue(plannedVal, plannedVal.Type())
66: 	if err != nil {
67: 		t.Fatal(err)
68: 	}
69: 
70: 	changes := plans.NewChangesSrc()
71: 	addr := addrs.Resource{
72: 		Mode: addrs.ManagedResourceMode,
73: 		Type: "test_resource",
74: 		Name: "foo",
75: 	}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance)
76: 
77: 	changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
78: 		Addr:        addr,
79: 		PrevRunAddr: addr,
80: 		ProviderAddr: addrs.AbsProviderConfig{
81: 			Provider: addrs.NewDefaultProvider("test"),
82: 			Module:   addrs.RootModule,
83: 		},
84: 		ChangeSrc: plans.ChangeSrc{
85: 			Action: plans.Create,
86: 			Before: priorValRaw,
87: 			After:  plannedValRaw,
88: 		},
89: 	})
90: 
91: 	return &plans.Plan{
92: 		Changes:   changes,
93: 		Applyable: true,
94: 		Complete:  true,
95: 	}
96: }
97: 
98: func testPlanWithDatasource(t *testing.T) *plans.Plan {
99: 	plan := testPlan(t)
100: 
101: 	addr := addrs.Resource{
102: 		Mode: addrs.DataResourceMode,
103: 		Type: "test_data_source",
104: 		Name: "bar",
105: 	}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance)
106: 
107: 	dataVal := cty.ObjectVal(map[string]cty.Value{
108: 		"id":  cty.StringVal("C6743020-40BD-4591-81E6-CD08494341D3"),
109: 		"bar": cty.StringVal("foo"),
110: 	})
111: 	priorValRaw, err := plans.NewDynamicValue(cty.NullVal(dataVal.Type()), dataVal.Type())
112: 	if err != nil {
113: 		t.Fatal(err)
114: 	}
115: 	plannedValRaw, err := plans.NewDynamicValue(dataVal, dataVal.Type())
116: 	if err != nil {
117: 		t.Fatal(err)
118: 	}
119: 
120: 	plan.Changes.AppendResourceInstanceChange(&plans.ResourceInstanceChangeSrc{
121: 		Addr:        addr,
122: 		PrevRunAddr: addr,
123: 		ProviderAddr: addrs.AbsProviderConfig{
124: 			Provider: addrs.NewDefaultProvider("test"),
125: 			Module:   addrs.RootModule,
126: 		},
127: 		ChangeSrc: plans.ChangeSrc{
128: 			Action: plans.Read,
129: 			Before: priorValRaw,
130: 			After:  plannedValRaw,
131: 		},
132: 	})
133: 
134: 	return plan
135: }
136: 
137: func testSchemas() *terraform.Schemas {
138: 	provider := testProvider()
139: 	return &terraform.Schemas{
140: 		Providers: map[addrs.Provider]providers.ProviderSchema{
141: 			addrs.NewDefaultProvider("test"): provider.GetProviderSchema(),
142: 		},
143: 	}
144: }
145: 
146: func testProvider() *testing_provider.MockProvider {
147: 	p := new(testing_provider.MockProvider)
148: 	p.ReadResourceFn = func(req providers.ReadResourceRequest) providers.ReadResourceResponse {
149: 		return providers.ReadResourceResponse{NewState: req.PriorState}
150: 	}
151: 
152: 	p.GetProviderSchemaResponse = testProviderSchema()
153: 
154: 	return p
155: }
156: 
157: func testProviderSchema() *providers.GetProviderSchemaResponse {
158: 	return &providers.GetProviderSchemaResponse{
159: 		Provider: providers.Schema{
160: 			Block: &configschema.Block{},
161: 		},
162: 		ResourceTypes: map[string]providers.Schema{
163: 			"test_resource": {
164: 				Block: &configschema.Block{
165: 					Attributes: map[string]*configschema.Attribute{
166: 						"id":  {Type: cty.String, Computed: true},
167: 						"foo": {Type: cty.String, Optional: true},
168: 					},
169: 				},
170: 			},
171: 		},
172: 		DataSources: map[string]providers.Schema{
173: 			"test_data_source": {
174: 				Block: &configschema.Block{
175: 					Attributes: map[string]*configschema.Attribute{
176: 						"id":  {Type: cty.String, Required: true},
177: 						"bar": {Type: cty.String, Optional: true},
178: 					},
179: 				},
180: 			},
181: 		},
182: 	}
183: }
